"use strict";

const Constants = Object.freeze({
  /**
   * The name of the icon rendered in the popup
   * @type {String}
   */
  ANNOTATE_ICON_NAME: "comment",
  /**
   * The keyboard shortcut that needs to be triggered to create an annotation
   * @type {KeyboardEventInit}
   */
  ANNOTATE_SHORTCUT: { ctrlKey: true, keyCode: 77 }, // ShortcutJS still expects the deprecated keyCode property
  /**
   * The translation key for the button title (for accessibility)
   * @type {String}
   */
  ANNOTATE_TRANSLATION_KEY: "action.create.submit.text",
  /**
   * The CSS class that needs to be added to show the popup
   * @type {String}
   */
  POPUP_CLASS_OPEN: "opened",
  /**
   * The element id of the popup
   * @type {String}
   */
  POPUP_ID: "annotation-popup"
});

// Icons API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Icon%20Theme%20Application#HJavaScriptAPI)
define("xwiki-annotate-popup/icons", {
  icons: [Constants.ANNOTATE_ICON_NAME]
});

// Translation API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Localization/#HFromJavaScript)
define("xwiki-annotate-popup/translation-keys", {
  prefix: "annotations.",
  keys: [Constants.ANNOTATE_TRANSLATION_KEY]
});

define("xwiki-annotate-popup", ["xwiki-icon!xwiki-annotate-popup/icons", "xwiki-l10n!xwiki-annotate-popup/translation-keys"], function(icons, l10n) {
   /**
    * Debounces a function
    * @param {number} delay - Delay time
    * @returns {Function} - Debounced version of func (result not returned)
    */
   function debounce(func, delay) {
      let timeout;
      return function (...args) {
          clearTimeout(timeout);
          timeout = setTimeout(() => { func.apply(this, args); }, delay);
      };
   }

   // shared module state (single popup instance)
   const state = {
     popup: null,
     popupButton: null,
     currentRect: null,
     previousFocusElem: null
   };

   /**
    * Inserts popup to DOM
    */
   function addPopupToDOM() {
      const popup = document.createElement("div");
      popup.id = Constants.POPUP_ID;
      popup.role = "dialog";
      popup.ariaHidden = true;

      const popupButton = document.createElement("button");
      popupButton.classList.add("btn", "btn-default", "btn-xs");
      popupButton.title = l10n[Constants.ANNOTATE_TRANSLATION_KEY];

      popupButton.appendChild(icons[Constants.ANNOTATE_ICON_NAME].render());
      popup.appendChild(popupButton);
      document.body.appendChild(popup);

      state.popup = popup;
      state.popupButton = popupButton;
   }

   /**
    * Close popup when pressing escape key
    * @param {KeyboardEvent} event
    */
   function onEscapeKey(event) {
     if (event.key !== "Escape") return;

      closePopup();
      document.removeEventListener("keydown", onEscapeKey);

      // restore focus
      if (state.previousFocusElem && typeof state.previousFocusElem.focus === "function") {
        state.previousFocusElem.focus();
      }
   }

   /**
    * Closes popup when clicking on the page
    * @returns {(event: ClickEvent) => void} - A debounced click listener
    */
   const onClickAway = debounce((event) => {
      // Check if the click was within the bounds of the original text selection
      const isClickInsideSelection = state.currentRect.left <= event.clientX &&
                                     event.clientX <= state.currentRect.right &&
                                     state.currentRect.top <= event.clientY &&
                                     event.clientY <= state.currentRect.bottom;

      if (!state.popup.contains(event.target) && !isClickInsideSelection) {
          closePopup();
          document.removeEventListener("click", onClickAway);
      }
    }, 60);

   const onViewportChange = debounce(() => {
      const { popupTop, popupLeft } = getPopupPositioning(window.getSelection());
      state.popup.style.top = popupTop;
      state.popup.style.left = popupLeft;
   }, 100);

   /**
    * Close the popup
    */
   function closePopup() {
      state.popup.classList.remove(Constants.POPUP_CLASS_OPEN);
      state.popup.ariaHidden = false;

      // remove event listeners
      document.removeEventListener("keydown", onEscapeKey);
      document.removeEventListener("click", onClickAway);
      window.visualViewport.removeEventListener("resize", onViewportChange);
   };


   /**
    * Get popup positioning (top and left absolute positioning)
    * @return {{popupTop: number, popupLeft: number}} The popup element and popup button
    */
   function getPopupPositioning(selection) {
      // use rect of last last line/element, important for correct positioning in multi-line selections
      const rects = selection.getRangeAt(0).getClientRects();
      if (!rects.length) return;
      state.currentRect = rects[rects.length - 1];

      const top = (state.currentRect.top + window.scrollY - state.popup.offsetHeight - 4) + "px"; // position 4px over selection so that the popup is not "attached" to the element
      const left = (state.currentRect.left + window.scrollX + state.currentRect.width - (state.popup.offsetWidth / 2)) + "px";

      return { popupTop: top, popupLeft: left };
   }

   /**
    * Displays the popup near the selected text range
    * @param {Selection} selection - A selection
    */
   function openPopup(selection) {
      const { popupTop, popupLeft } = getPopupPositioning(selection);
      state.popup.style.top = popupTop;
      state.popup.style.left = popupLeft;

      state.popup.classList.add(Constants.POPUP_CLASS_OPEN);
      state.popup.ariaHidden = false;

      // focus popup button
      state.previousFocusElem = document.activeElement;
      state.popupButton.focus();

      // add event listeners
      document.addEventListener("keydown", onEscapeKey); // close on escape key
      document.addEventListener("click", onClickAway); // close on click away
      window.visualViewport.addEventListener("resize", onViewportChange); // reposition on viewport change
   }

   /**
    * Register event listeners
    * @param {HTMLElement} wikiContent - The XWiki page container
    */
   function registerListeners(wikiContent) {
      // add click listener to button
      state.popupButton.addEventListener("click", () => {
         closePopup();
         document.dispatchEvent(new KeyboardEvent("keydown", Constants.ANNOTATE_SHORTCUT));
      });

      // allow pressing enter to click button
      state.popupButton.addEventListener("keydown", (e) => {
        if (e.key !== "Enter") return;

        e.preventDefault();
        state.popupButton.click();
      });

      /**
       * Checks the current selection and opens the popup
       */
      function onSelectionChange() {
         closePopup(); // close on new select

         const selection = window.getSelection();
         if (!selection || selection.rangeCount === 0 | !selection.toString() || !wikiContent.contains(selection.anchorNode)) {
             return;
         }

         openPopup(selection);
      }
      const selectionListener = debounce(onSelectionChange, 800);
      document.addEventListener("selectionchange", selectionListener, { passive: true });

      // Disable annotation popup in edit mode
      wikiContent.on("xwiki:actions:edit", () => { document.removeEventListener("selectionchange", selectionListener); });
      wikiContent.on("xwiki:actions:view", () => { document.addEventListener("selectionchange", selectionListener, { passive: true }); });

      state.popup.addEventListener("pointerdown", (event) => { event.preventDefault(); });  // prevent losing focus (the selection) when clicking on popup edges

      // TODO: disable popup when annotation dialog is open?
   }

   class AnnotatePopup {
      constructor(wikiContent) {
         this.wikiContent = wikiContent;
         this.popup = null;
         this.annotateButton = null;
         this.currentRect = null;
         this.previousFocus = null;

        // bind handlers once so removeEventListener works
        this.handlePointerDown = this.handlePointerDown.bind(this);
        this.handleKeyDown = this.handleKeyDown.bind(this);
        this.onClickAway = debounce(this.onClickAway.bind(this), 60);
        this.onViewportChange = debounce(this.onViewportChange.bind(this), 100);

        this.createPopup();
        this.registerListeners();
      }
   }

   /**
    * Initialize AnnotatePopupInline
    * @param {HTMLElement} wikiContent - The XWiki page container
    */
   function init(wikiContent) {
      const popupInstance = new AnnotatePopup(wikiContent);

      addPopupToDOM();
      registerListeners(wikiContent);
   }

   return init;
});

#annotation-popup {
   position: absolute;
   background-color: var(--xwiki-page-content-bg);
   padding: 4px;
   border-radius: 4px;
   box-shadow: 0 1.65px 3px var(--btn-default-border);
   display: none; // to prevent event delivery
   visibility: hidden;
   opacity: 0;
   transition: opacity .2s ease-in;
   &.opened {
      display: block;
      visibility: visible;
      opacity: 1;
   }
}
